class Solution:
    def maxAreaOfIsland(self, grid):
        # Union-find based independent approach.
        m = len(grid)
        n = len(grid[0]) if m else 0
        parent = list(range(m * n))
        def find(x):
            while parent[x] != x:
                parent[x] = parent[parent[x]]
                x = parent[x]
            return x
        def union(a, b):
            ra, rb = find(a), find(b)
            if ra != rb:
                parent[ra] = rb
        for i in range(m):
            for j in range(n):
                if grid[i][j] == 1:
                    if i + 1 < m and grid[i + 1][j] == 1:
                        union(i * n + j, (i + 1) * n + j)
                    if j + 1 < n and grid[i][j + 1] == 1:
                        union(i * n + j, i * n + j + 1)
        from collections import defaultdict
        sizes = defaultdict(int)
        best = 0
        for i in range(m):
            for j in range(n):
                if grid[i][j] == 1:
                    r = find(i * n + j)
                    sizes[r] += 1
                    best = max(best, sizes[r])
        return best

