var maxAreaOfIsland = function(grid) {
    const m = grid.length, n = grid[0].length;
    let best = 0;
    for (let i = 0; i < m; i++) {
        for (let j = 0; j < n; j++) {
            if (grid[i][j] === 1) {
                let area = 0;
                const stack = [[i, j]];
                grid[i][j] = 0;
                while (stack.length) {
                    const [x, y] = stack.pop();
                    area++;
                    for (const [dx, dy] of [[1,0],[-1,0],[0,1],[0,-1]]) {
                        const nx = x + dx, ny = y + dy;
                        if (nx >= 0 && nx < m && ny >= 0 && ny < n && grid[nx][ny] === 1) {
                            grid[nx][ny] = 0;
                            stack.push([nx, ny]);
                        }
                    }
                }
                best = Math.max(best, area);
            }
        }
    }
    return best;
};
